// Filter, sort, and keep top 5 repos
const items = $input.first().json;

if (!items || !items.items || items.items.length === 0) {
  throw new Error('No repositories returned from GitHub API');
}

const top5 = items.items
  .filter(repo => !repo.fork && repo.description)
  .sort((a, b) => b.stargazers_count - a.stargazers_count)
  .slice(0, 5)
  .map((repo, index) => ({
    rank: index + 1,
    name: repo.full_name,
    url: repo.html_url,
    description: repo.description ? repo.description.substring(0, 150) : 'No description',
    stars: repo.stargazers_count,
    forks: repo.forks_count,
    language: repo.language || 'Unknown',
    open_issues: repo.open_issues_count,
    updated_at: repo.updated_at,
    owner: repo.owner.login,
    default_branch: repo.default_branch
  }));

return top5.map(repo => ({ json: repo }));

// Format popular repos with README enrichment data
const items = $input.all();
return items.map(item => {
  const repo = item.json;
  let readmeUrl = '';

  if (repo.download_url) {
    readmeUrl = repo.download_url;
  } else if (repo.html_url) {
    readmeUrl = repo.html_url;
  }

  return {
    json: {
      rank: repo.rank || '⭐',
      name: repo.name || repo.full_name || 'Unknown',
      url: repo.url || '',
      description: repo.description || 'No description',
      stars: repo.stars || repo.stargazers_count || 0,
      forks: repo.forks || repo.forks_count || 0,
      language: repo.language || 'Unknown',
      open_issues: repo.open_issues || 0,
      readme_url: readmeUrl,
      category: '🔥 Popular',
      enriched: !!repo.download_url
    }
  };
});

// Format non-popular repos as "Rising" category
const items = $input.all();
return items.map(item => {
  const repo = item.json;
  return {
    json: {
      rank: repo.rank,
      name: repo.name,
      url: repo.url,
      description: repo.description,
      stars: repo.stars,
      forks: repo.forks,
      language: repo.language,
      open_issues: repo.open_issues,
      readme_url: '',
      category: '📦 Rising',
      enriched: false
    }
  };
});

// Build the final digest message for Discord
const items = $input.all();
const now = new Date().toISOString().split('T')[0];

let message = '\u{1F680} **Daily Tech Digest \u2014 ' + now + '**\n\n';
message += '**Top JavaScript Repositories**\n\n';

const popular = items.filter(i => i.json.category === '\u{1F525} Popular');
const rising = items.filter(i => i.json.category === '\u{1F4E6} Rising');

if (popular.length > 0) {
  message += '**\u{1F525} Popular (>1000 stars)**\n';
  popular.forEach(i => {
    const r = i.json;
    message += '\n**' + r.rank + '. ' + r.name + '** \u2014 \u2B50 ' + r.stars.toLocaleString() + ' | Forks: ' + r.forks + '\n';
    message += '> ' + r.description + '\n';
    message += '> Link: ' + r.url + '\n';
    if (r.readme_url) {
      message += '> README: ' + r.readme_url + '\n';
    }
  });
}

if (rising.length > 0) {
  message += '\n**\u{1F4E6} Rising**\n';
  rising.forEach(i => {
    const r = i.json;
    message += '\n**' + r.rank + '. ' + r.name + '** \u2014 \u2B50 ' + r.stars.toLocaleString() + ' | Forks: ' + r.forks + '\n';
    message += '> ' + r.description + '\n';
    message += '> Link: ' + r.url + '\n';
  });
}

message += '\n---\n_Generated by n8n at ' + new Date().toISOString() + '_';

return [{ json: { digest: message.substring(0, 2000), repo_count: items.length, timestamp: new Date().toISOString() } }];

// Log the GitHub API error
const errorData = $input.all();
const errorMessage = errorData.length > 0 ? JSON.stringify(errorData[0].json) : 'Unknown error';
const timestamp = new Date().toISOString();

console.error(`[${timestamp}] Workflow Error: ${errorMessage}`);

return [{
  json: {
    error: true,
    timestamp: timestamp,
    message: 'GitHub API call failed. Possible causes: rate limiting (60 req/hr unauthenticated), network timeout, or API outage.',
    raw_error: errorMessage,
    action: 'Will retry on next scheduled run (1 hour)'
  }
}];

// Graceful fallback when Discord itself fails
const timestamp = new Date().toISOString();
console.error(`[${timestamp}] Discord delivery failed. Digest was generated but not delivered.`);

return [{
  json: {
    fallback: true,
    message: 'Discord notification failed. Digest generated but not delivered.',
    timestamp: timestamp
  }
}];
